<script setup lang="ts">import {nextTick, ref, watch } from "vue";import {convertSecondsToTime} from "../../../utils/DateUtil.ts";import WaveSurfer, {WaveSurferOptions} from "wavesurfer.js";import {themeConfig} from "../composables/ThemeEditorDataComposable.ts";// 音乐播放器相关// Wavesurfer 实例let wavesurfer: WaveSurfer;const isLoadingWaveform = ref(false);const currentTime = ref<number>(0); // 当前播放时间const duration = ref(0); // 音频时长/** * 获取 Wavesurfer 选项 */const getWavesurferOptions = (): WaveSurferOptions => {  return {    container: '#waveformContainer',    waveColor: themeConfig.wavesurfer.waveColor,    cursorColor: themeConfig.wavesurfer.cursorColor,    progressColor: themeConfig.wavesurfer.progressColor,    height: 90,    cursorWidth: 2,    barWidth: 2,    barRadius: 2,    barGap: 1,    normalize: true,    backend: 'MediaElement',    mediaControls: false, // 不显示默认的媒体控件    autoplay: false,    // 音乐文件来源于网络，侵权联系删除    url: '/video.mp3',    interact: true, // 启用与波形的交互（点击/拖拽改变播放位置）    dragToSeek: true, // 启用拖拽 seek  } as WaveSurferOptions;}/** * 初始化 Wavesurfer */const initWavesurfer = (): void => {  isLoadingWaveform.value = true;  nextTick(() => {    console.log('初始化 Wavesurfer');    // 初始化 Wavesurfer 实例    wavesurfer = WaveSurfer.create(getWavesurferOptions());    // --- Wavesurfer 事件监听 ---    wavesurfer.on('ready', () => {      console.log('Wavesurfer 加载完成');      duration.value = wavesurfer.getDuration();      isLoadingWaveform.value = false;    });    // 监听用户点击/拖拽波形改变播放位置    wavesurfer.on('interaction', (newTime) => {      currentTime.value = newTime;    });    // 监听主题切换    watch(themeConfig, () => {      wavesurfer.setOptions(getWavesurferOptions());    })  })}/** * 拖动进度条 */const onSeek = () => {  if (wavesurfer && duration.value > 0) {    const progress = currentTime.value / duration.value;    wavesurfer.seekTo(progress);  }}</script><template>  <n-collapse-item class="custom-theme-collapse-item" title="音频组件" name="4" @click="initWavesurfer">    <div class="waveform-wrapper">      <div v-show="isLoadingWaveform" class="waveform-loading">        <n-spin/>      </div>      <div v-show="!isLoadingWaveform">        <!-- Wavesurfer 波形显示区域 -->        <div id="waveformContainer" class="waveform-container"></div>        <!-- 播放进度 -->        <n-slider            class="progress-slider"            :min="0"            :max="duration"            v-model:value="currentTime"            :step="1"            @update:value="onSeek"            :format-tooltip="(val:number) => {return convertSecondsToTime(val)}"        />        <div class="progress-container">          <span>{{ convertSecondsToTime(currentTime) }}</span>          <span>{{ convertSecondsToTime(duration) }}</span>        </div>      </div>    </div>  </n-collapse-item></template><style scoped>/* 音频组件 start */.waveform-wrapper {  padding: 10px;}.waveform-loading {  width: 100%;  display: flex;  align-items: center;  justify-content: center;}.waveform-container {  background-color: var(--preview-universal-secondary);  border: 2px solid var(--preview-universal-border);  padding: 8px;  border-radius: 8px;}.progress-slider {  margin-top: 10px;  margin-bottom: 5px;}.progress-container {  width: 98%;  display: flex;  justify-content: space-between;  padding: 0 1%;}/* 音频组件 end */</style>